example.code:
services: app: build: context: . target: production image: myapp:${VERSION:-latest} container_name: ${PROJECT_NAME}-app restart: unless-stopped environment: DATABASE_URL: postgres://app:${DB_PASSWORD}@db:5432/appdb REDIS_URL: redis://redis:6379/0 env_file: [.env] depends_on: db: condition: service_healthy redis: condition: service_healthy healthcheck: test: ["CMD", "curl", "-f", "http://localhost:8000/health"] interval: 30s timeout: 10s retries: 3 start_period: 40s deploy: resources: limits: {memory: 512M, cpus: "1.0"} reservations: {memory: 128M} networks: [frontend, backend] logging: driver: json-file options: {max-size: "10m", max-file: "3"}
db: image: postgres:16-alpine container_name: ${PROJECT_NAME}-db restart: unless-stopped environment: POSTGRES_USER: app POSTGRES_PASSWORD: ${DB_PASSWORD} POSTGRES_DB: appdb PGDATA: /var/lib/postgresql/data/pgdata volumes: - postgres-data:/var/lib/postgresql/data healthcheck: test: ["CMD-SHELL", "pg_isready -U app -d appdb"] interval: 10s timeout: 5s retries: 5 networks: [backend] deploy: resources: limits: {memory: 256M, cpus: "0.5"}
redis: image: redis:7-alpine container_name: ${PROJECT_NAME}-redis restart: unless-stopped command: redis-server --appendonly yes --maxmemory ${REDIS_MAXMEM:-100mb} --maxmemory-policy allkeys-lru volumes: - redis-data:/data healthcheck: test: ["CMD", "redis-cli", "ping"] interval: 10s timeout: 5s retries: 5 networks: [backend] deploy: resources: limits: {memory: 128M, cpus: "0.25"}
nginx: image: nginx:alpine container_name: ${PROJECT_NAME}-nginx restart: unless-stopped ports: - "80:80" - "443:443" volumes: - ./nginx/conf.d:/etc/nginx/conf.d:ro - ./certbot/conf:/etc/letsencrypt:ro depends_on: [app] networks: [frontend]
worker: build: {context: ., target: production} image: myapp:${VERSION:-latest} container_name: ${PROJECT_NAME}-worker restart: unless-stopped command: celery -A app worker --loglevel=info env_file: [.env] depends_on: db: condition: service_healthy redis: condition: service_healthy networks: [backend] deploy: resources: limits: {memory: 256M, cpus: "0.5"} profiles: [worker]
networks: frontend: driver: bridge backend: driver: bridge internal: true
volumes: postgres-data: redis-data:
